     1→/**
     2→ * Jiranimo content script.
     3→ * Runs on Jira sprint board pages.
     4→ * Detects cards with the trigger label (via Jira API) and injects "Implement" badges.
     5→ * Polls the local server for task status updates.
     6→ */
     7→
     8→// @ts-check
     9→/* global chrome, BoardConfig */
    10→
    11→(function () {
    12→  'use strict';
    13→
    14→  const LOG_PREFIX = '[Jiranimo]';
    15→  const log = (...args) => console.log(LOG_PREFIX, ...args);
    16→  const warn = (...args) => console.warn(LOG_PREFIX, ...args);
    17→
    18→  const BADGE_ATTR = 'data-jiranimo';
    19→  const SCAN_DEBOUNCE = 500;
    20→  const WS_RECONNECT_DELAY = 3000;
    21→  const SPARKLES_SVG = '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor"><path fill-rule="evenodd" d="M9 4.5a.75.75 0 01.721.544l.813 2.846a3.75 3.75 0 002.576 2.576l2.846.813a.75.75 0 010 1.442l-2.846.813a3.75 3.75 0 00-2.576 2.576l-.813 2.846a.75.75 0 01-1.442 0l-.813-2.846a3.75 3.75 0 00-2.576-2.576l-2.846-.813a.75.75 0 010-1.442l2.846-.813A3.75 3.75 0 007.466 7.89l.813-2.846A.75.75 0 019 4.5zM18 1.5a.75.75 0 01.728.568l.258 1.036c.236.94.97 1.674 1.91 1.91l1.036.258a.75.75 0 010 1.456l-1.036.258c-.94.236-1.674.97-1.91 1.91l-.258 1.036a.75.75 0 01-1.456 0l-.258-1.036a2.625 2.625 0 00-1.91-1.91l-1.036-.258a.75.75 0 010-1.456l1.036-.258a2.625 2.625 0 001.91-1.91l.258-1.036A.75.75 0 0118 1.5zM16.5 15a.75.75 0 01.712.513l.394 1.183c.15.447.5.799.948.948l1.183.395a.75.75 0 010 1.422l-1.183.395c-.447.15-.799.5-.948.948l-.395 1.183a.75.75 0 01-1.422 0l-.395-1.183a1.5 1.5 0 00-.948-.948l-1.183-.395a.75.75 0 010-1.422l1.183-.395c.447-.15.799-.5.948-.948l.395-1.183A.75.75 0 0116.5 15z" clip-rule="evenodd"/></svg>';
    22→
    23→  /** @type {Record<string, string>} taskKey -> status */
    24→  let taskStatuses = {};
    25→  /** @type {Record<string, string>} taskKey -> prUrl */
    26→  let taskPrUrls = {};
    27→
    28→  // Restore task statuses from sessionStorage so animations survive page reloads
    29→  try {
    30→    const saved = JSON.parse(sessionStorage.getItem('jiranimo-statuses') || '{}');
    31→    const savedUrls = JSON.parse(sessionStorage.getItem('jiranimo-prurls') || '{}');
    32→    Object.assign(taskStatuses, saved);
    33→    Object.assign(taskPrUrls, savedUrls);
    34→    log('Restored', Object.keys(saved).length, 'task statuses from sessionStorage');
    35→  } catch { /* ignore */ }
    36→
    37→  function persistStatuses() {
    38→    try {
    39→      sessionStorage.setItem('jiranimo-statuses', JSON.stringify(taskStatuses));
    40→      sessionStorage.setItem('jiranimo-prurls', JSON.stringify(taskPrUrls));
    41→    } catch { /* ignore */ }
    42→  }
    43→
    44→  /** @type {string} */
    45→  let serverUrl = 'http://localhost:3456';
    46→  /** @type {object|null} */
    47→  let boardConfig = null;
    48→  /** @type {number|null} */
    49→  let scanTimer = null;
    50→  /** @type {string|null} */
    51→  let currentBoardId = null;
    52→  /** @type {Array<{key: string, summary: string, labels: string[]}>|null} */
    53→  let cachedSprintIssues = null;
    54→
    55→  async function init() {
    56→    log('Content script loaded on', location.href);
    57→
    58→    const settings = await chrome.storage.local.get(['serverUrl']);
    59→    serverUrl = settings.serverUrl || 'http://localhost:3456';
    60→    log('Config — serverUrl:', serverUrl);
    61→
    62→    currentBoardId = getBoardId();
    63→    if (!currentBoardId) {
    64→      warn('Could not extract board ID from URL');
    65→      return;
    66→    }
    67→    log('Board ID:', currentBoardId);
    68→
    69→    const stored = await chrome.storage.local.get([`boardConfig_${currentBoardId}`]);
    70→    boardConfig = stored[`boardConfig_${currentBoardId}`] || null;
    71→
    72→    if (!boardConfig) {
    73→      log('No board config found — showing setup modal');
    74→      BoardConfig.show(currentBoardId, (config) => {
    75→        boardConfig = config;
    76→        startScanning();
    77→      });
    78→    } else {
    79→      log('Board config loaded:', JSON.stringify(boardConfig));
    80→      startScanning();
    81→    }
    82→  }
    83→
    84→  function getBoardId() {
    85→    const match = location.pathname.match(/\/boards\/(\d+)/);
    86→    return match ? match[1] : null;
    87→  }
    88→
    89→  function startScanning() {
    90→    log('Starting card scanner');
    91→    setTimeout(() => scanCards(), 1000);
    92→    observeCardChanges();
    93→    connectWebSocket();
    94→  }
    95→
    96→  function debouncedScan() {
    97→    if (scanTimer) clearTimeout(scanTimer);
    98→    scanTimer = setTimeout(() => scanCards(), SCAN_DEBOUNCE);
    99→  }
   100→
   101→  async function scanCards() {
   102→    if (!cachedSprintIssues) {
   103→      cachedSprintIssues = await fetchSprintIssues();
   104→    }
   105→    if (!cachedSprintIssues) {
   106→      log('No sprint issues found');
   107→      return;
   108→    }
   109→    log(`Scanning ${cachedSprintIssues.length} sprint issues`);
   110→
   111→    const triggerLabel = boardConfig?.triggerLabel;
   112→    let injected = 0;
   113→    for (const issue of cachedSprintIssues) {
   114→      const key = issue.key;
   115→      if (triggerLabel && !issue.labels.includes(triggerLabel)) continue;
   116→      if (document.querySelector(`[${BADGE_ATTR}="${key}"]`)) continue;
   117→      const titleEl = findIssueTitleElement(key);
   118→      if (!titleEl) continue;
   119→      injectBadge(titleEl, key);
   120→      injected++;
   121→    }
   122→    log(`Injected ${injected} badges`);
   123→  }
   124→
   125→  async function fetchSprintIssues() {
   126→    try {
   127→      const sprintRes = await fetch(
   128→        `${location.origin}/rest/agile/1.0/board/${currentBoardId}/sprint?state=active`,
   129→        { credentials: 'include' }
   130→      );
   131→      if (!sprintRes.ok) { warn('Failed to fetch active sprint:', sprintRes.status); return null; }
   132→      const sprintData = await sprintRes.json();
   133→      const sprint = sprintData.values?.[0];
   134→      if (!sprint) { warn('No active sprint found'); return null; }
   135→      log('Active sprint:', sprint.name);
   136→
   137→      const issueRes = await fetch(
   138→        `${location.origin}/rest/agile/1.0/sprint/${sprint.id}/issue?fields=summary,labels&maxResults=200`,
   139→        { credentials: 'include' }
   140→      );
   141→      if (!issueRes.ok) { warn('Failed to fetch sprint issues:', issueRes.status); return null; }
   142→      const issueData = await issueRes.json();
   143→      return (issueData.issues || []).map(i => ({ key: i.key, summary: i.fields.summary, labels: i.fields.labels || [] }));
   144→    } catch (err) {
   145→      warn('fetchSprintIssues error:', err);
   146→      return null;
   147→    }
   148→  }
   149→
   150→  function findIssueTitleElement(issueKey) {
   151→    for (const el of document.querySelectorAll('div, a, span')) {
   152→      if (el.childElementCount === 0 && el.textContent.trim() === issueKey) {
   153→        log(`findIssueTitleElement: found key element for ${issueKey}`);
   154→        return el;
   155→      }
   156→    }
   157→    log(`findIssueTitleElement: no element found for ${issueKey}`);
   158→    return null;
   159→  }
   160→
   161→  /**
   162→   * Fetch labels for multiple issues via Jira REST API using JQL search.
   163→   */
   164→
   165→  /**
   166→   * Fetch full issue details from Jira REST API (content script has session cookies).
   167→   * Returns data ready to POST to the server.
   168→   */
   169→  async function fetchIssueDetails(issueKey) {
   170→    try {
   171→      const fields = 'summary,description,priority,issuetype,labels,comment,status,subtasks,parent,issuelinks,assignee,reporter,components,attachment';
   172→      const url = `${location.origin}/rest/api/3/issue/${issueKey}?fields=${fields}&expand=renderedFields`;
   173→      log('Fetching issue details:', issueKey);
   174→      const res = await fetch(url, { credentials: 'include' });
   175→      if (!res.ok) {
   176→        warn('Issue fetch failed:', res.status);
   177→        return null;
   178→      }
   179→      const issue = await res.json();
   180→      const f = issue.fields;
   181→
   182→      // Convert ADF description to plain text
   183→      let description = '';
   184→      if (f.description) {
   185→        description = extractTextFromAdf(f.description);
   186→      }
   187→      if (!description && issue.renderedFields?.description) {
   188→        description = issue.renderedFields.description.replace(/<[^>]+>/g, '');
   189→      }
   190→
   191→      return {
   192→        key: issueKey,
   193→        summary: f.summary || issueKey,
   194→        description: description || f.summary || '',
   195→        priority: f.priority?.name || 'Medium',
   196→        issueType: f.issuetype?.name || 'Task',
   197→        labels: f.labels || [],
   198→        comments: (f.comment?.comments || []).slice(-10).map(c => ({
   199→          author: c.author?.displayName || 'Unknown',
   200→          body: extractTextFromAdf(c.body),
   201→          created: c.created,
   202→        })),
   203→        subtasks: (f.subtasks || []).map(s => ({
   204→          key: s.key,
   205→          summary: s.fields?.summary || '',
   206→          status: s.fields?.status?.name || '',
   207→        })),
   208→        linkedIssues: (f.issuelinks || []).map(l => {
   209→          const linked = l.outwardIssue || l.inwardIssue;
   210→          return { type: l.type?.outward || 'related', key: linked?.key || '', summary: linked?.fields?.summary || '', status: linked?.fields?.status?.name || '' };
   211→        }).filter(l => l.key),
   212→        attachments: (f.attachment || []).map(a => ({ filename: a.filename, mimeType: a.mimeType, url: a.content })),
   213→        assignee: f.assignee?.displayName || '',
   214→        reporter: f.reporter?.displayName || '',
   215→        components: (f.components || []).map(c => c.name),
   216→        parentKey: f.parent?.key || '',
   217→        jiraUrl: `${location.origin}/browse/${issueKey}`,
   218→        projectKey: issueKey.split('-')[0],
   219→      };
   220→    } catch (err) {
   221→      warn('fetchIssueDetails error:', err);
   222→      return null;
   223→    }
   224→  }
   225→
   226→  /**
   227→   * Transition a Jira issue by name. Fetches available transitions,
   228→   * finds the matching one, and executes it. Done directly from the
   229→   * content script so session cookies are available (works in incognito).
   230→   */
   231→  async function transitionIssue(issueKey, transitionName) {
   232→    try {
   233→      log(`Transitioning ${issueKey} to "${transitionName}"`);
   234→      const transRes = await fetch(`${location.origin}/rest/api/3/issue/${issueKey}/transitions`, { credentials: 'include' });
   235→      if (!transRes.ok) { warn('Failed to get transitions:', transRes.status); return; }
   236→      const data = await transRes.json();
   237→      const match = (data.transitions || []).find(t => t.name.toLowerCase() === transitionName.toLowerCase());
   238→      if (!match) { warn(`Transition "${transitionName}" not found. Available:`, (data.transitions || []).map(t => t.name)); return; }
   239→      const execRes = await fetch(`${location.origin}/rest/api/3/issue/${issueKey}/transitions`, {
   240→        method: 'POST',
   241→        headers: { 'Content-Type': 'application/json' },
   242→        credentials: 'include',
   243→        body: JSON.stringify({ transition: { id: match.id } }),
   244→      });
   245→      if (execRes.ok) {
   246→        log(`Transitioned ${issueKey} to "${match.name}" — refreshing board`);
   247→        // Brief delay for Jira to process, then reload so the card appears in the new column
   248→        setTimeout(() => location.reload(), 500);
   249→      } else {
   250→        warn(`Transition failed: ${execRes.status}`);
   251→      }
   252→    } catch (err) { warn('transitionIssue error:', err); }
   253→  }
   254→
   255→  /**
   256→   * Post a comment on a Jira issue directly from the content script.
   257→   */
   258→  async function postJiraComment(issueKey, text) {
   259→    try {
   260→      await fetch(`${location.origin}/rest/api/3/issue/${issueKey}/comment`, {
   261→        method: 'POST',
   262→        headers: { 'Content-Type': 'application/json' },
   263→        credentials: 'include',
   264→        body: JSON.stringify({
   265→          body: { type: 'doc', version: 1, content: [{ type: 'paragraph', content: [{ type: 'text', text }] }] },
   266→        }),
   267→      });
   268→      log(`Comment posted on ${issueKey}`);
   269→    } catch (err) { warn('postJiraComment error:', err); }
   270→  }
   271→
   272→  /**
   273→   * Post a concise completion comment on the Jira issue.
   274→   * Includes PR link if available, and Claude's result summary if useful.
   275→   */
   276→  async function postCompletionComment(task) {
   277→    const parts = [];
   278→
   279→    if (task.prUrl) {
   280→      parts.push(`Draft PR: ${task.prUrl}`);
   281→    }
   282→
   283→    // Include Claude's summary if it's substantive (not just "done")
   284→    if (task.claudeResultText) {
   285→      const text = task.claudeResultText.trim();
   286→      // Only include if it's more than a trivial response
   287→      if (text.length > 10 && text.length < 2000) {
   288→        parts.push(text);
   289→      }
   290→    }
   291→
   292→    if (task.claudeCostUsd) {
   293→      parts.push(`Cost: $${task.claudeCostUsd.toFixed(2)}`);
   294→    }
   295→
   296→    if (parts.length === 0) {
   297→      parts.push('Done');
   298→    }
   299→
   300→    parts.push('\n— Jiranimo + Claude Code');
   301→
   302→    await postJiraComment(task.key, parts.join('\n\n'));
   303→  }
   304→
   305→  /** Simple recursive ADF text extractor */
   306→  function extractTextFromAdf(node) {
   307→    if (!node) return '';
   308→    if (node.type === 'text') return node.text || '';
   309→    if (node.type === 'hardBreak') return '\n';
   310→    if (Array.isArray(node.content)) return node.content.map(extractTextFromAdf).join('');
   311→    if (node.type === 'doc' && Array.isArray(node.content)) return node.content.map(extractTextFromAdf).join('\n\n');
   312→    return '';
   313→  }
   314→
   315→  function injectBadge(titleEl, issueKey) {
   316→    const icon = document.createElement('span');
   317→    icon.setAttribute(BADGE_ATTR, issueKey);
   318→    icon.className = 'jiranimo-icon idle';
   319→    icon.title = 'Implement with AI';
   320→    icon.innerHTML = SPARKLES_SVG;
   321→
   322→    const currentStatus = taskStatuses[issueKey];
   323→    if (currentStatus) {
   324→      updateBadgeState(icon, issueKey, currentStatus);
   325→    }
   326→
   327→    icon.addEventListener('click', (e) => {
   328→      e.preventDefault();
   329→      e.stopPropagation();
   330→      handleBadgeClick(icon, issueKey);
   331→    });
   332→
   333→    const wrapper = document.createElement('span');
   334→    wrapper.style.cssText = 'display: inline-flex; align-items: center; flex-direction: row; direction: ltr;';
   335→    titleEl.parentNode.insertBefore(wrapper, titleEl);
   336→    wrapper.appendChild(titleEl);
   337→    wrapper.appendChild(icon);
   338→    log(`Icon injected for ${issueKey}`);
   339→  }
   340→
   341→  function setBadgeState(icon, issueKey, status, titleOverride) {
   342→    updateBadgeState(icon, issueKey, status);
   343→    if (titleOverride) icon.title = titleOverride;
   344→  }
   345→
   346→  /** Proxy server API calls through the background service worker to avoid
   347→   *  Chrome's Private Network Access block (atlassian.net → localhost).
   348→   * @param {string} path
   349→   * @param {string} [method]
   350→   * @param {unknown} [body]
   351→   */
   352→  function serverFetch(path, method, body) {
   353→    return new Promise((resolve, reject) => {
   354→      // @ts-ignore — chrome global is declared at top of file
   355→      chrome.runtime.sendMessage(
   356→        { type: 'server-fetch', path, method: method || 'GET', body },
   357→        // @ts-ignore
   358→        (response) => {
   359→          // @ts-ignore
   360→          if (chrome.runtime.lastError) { reject(new Error(chrome.runtime.lastError.message)); return; }
   361→          if (!response) { reject(new Error('No response from background')); return; }
   362→          resolve(response);
   363→        }
   364→      );
   365→    });
   366→  }
   367→
   368→  async function handleBadgeClick(icon, issueKey) {
   369→    const status = taskStatuses[issueKey];
   370→
   371→    if (status === 'failed') {
   372→      setBadgeState(icon, issueKey, 'in-progress', 'Retrying...');
   373→      try {
   374→        await serverFetch(`/api/tasks/${issueKey}/retry`, 'POST');
   375→      } catch (err) {
   376→        setBadgeState(icon, issueKey, 'failed', 'Error — click to retry');
   377→      }
   378→      return;
   379→    }
   380→
   381→    if (status === 'queued' || status === 'in-progress') return;
   382→
   383→    if (status === 'completed' && taskPrUrls[issueKey]) {
   384→      window.open(taskPrUrls[issueKey], '_blank');
   385→      return;
   386→    }
   387→
   388→    setBadgeState(icon, issueKey, 'in-progress', 'Sending to server...');
   389→
   390→    try {
   391→      const issueData = await fetchIssueDetails(issueKey);
   392→      if (!issueData) {
   393→        setBadgeState(icon, issueKey, 'failed', 'Failed to fetch issue — click to retry');
   394→        return;
   395→      }
   396→
   397→      /** @type {any} */
   398→      const result = await serverFetch('/api/tasks', 'POST', issueData);
   399→
   400→      if (result.ok) {
   401→        updateBadgeState(icon, issueKey, 'queued');
   402→        taskStatuses[issueKey] = 'queued';
   403→        persistStatuses();
   404→
   405→        if (boardConfig?.transitions?.inProgress) {
   406→          transitionIssue(issueKey, boardConfig.transitions.inProgress.name);
   407→        }
   408→      } else {
   409→        setBadgeState(icon, issueKey, 'failed', (result.data?.error || `Error ${result.status}`) + ' — click to retry');
   410→      }
   411→    } catch (err) {
   412→      warn('Implement failed (is the server running?):', err);
   413→      setBadgeState(icon, issueKey, 'failed', 'Server offline — click to retry');
   414→    }
   415→  }
   416→
   417→  function updateBadgeState(icon, issueKey, status) {
   418→    const label = icon.querySelector('.jiranimo-label');
   419→    switch (status) {
   420→      case 'queued':
   421→        icon.className = 'jiranimo-icon queued';
   422→        icon.title = 'Queued';
   423→        if (label) label.textContent = 'Queued';
   424→        break;
   425→      case 'in-progress':
   426→        icon.className = 'jiranimo-icon in-progress';
   427→        icon.title = 'Running...';
   428→        if (label) label.textContent = 'Running...';
   429→        break;
   430→      case 'completed':
   431→        icon.className = 'jiranimo-icon completed';
   432→        icon.title = 'PR ready — click to open';
   433→        if (label) label.textContent = 'Done';
   434→        break;
   435→      case 'failed':
   436→        icon.className = 'jiranimo-icon failed';
   437→        icon.title = 'Failed — click to retry';
   438→        if (label) label.textContent = 'Failed';
   439→        break;
   440→      default:
   441→        icon.className = 'jiranimo-icon idle';
   442→        icon.title = 'Implement with AI';
   443→        if (label) label.textContent = 'Implement';
   444→    }
   445→  }
   446→
   447→  function observeCardChanges() {
   448→    const observer = new MutationObserver(() => {
   449→      debouncedScan();
   450→    });
   451→    observer.observe(document.body, { childList: true, subtree: true });
   452→    log('MutationObserver attached');
   453→  }
   454→
   455→  /** @type {WebSocket|null} */
   456→  let ws = null;
   457→
   458→  async function syncTaskStatuses() {
   459→    try {
   460→      /** @type {any} */
   461→      const syncResult = await serverFetch('/api/tasks');
   462→      if (!syncResult.ok) return;
   463→      const tasks = syncResult.data;
   464→
   465→      // Collect completed/failed task keys to check against Jira
   466→      const toCheck = tasks.filter(t => t.status === 'completed' || t.status === 'failed');
   467→
   468→      // Check if any completed/failed tasks were moved back to To Do in Jira
   469→      const resetKeys = new Set();
   470→      if (toCheck.length > 0) {
   471→        const keys = toCheck.map(t => t.key);
   472→        try {
   473→          const jql = `key in (${keys.join(',')})`;
   474→          const jiraRes = await fetch(`${location.origin}/rest/api/3/search/jql`, {
   475→            method: 'POST',
   476→            headers: { 'Content-Type': 'application/json' },
   477→            credentials: 'include',
   478→            body: JSON.stringify({ jql, fields: ['status'], maxResults: 50 }),
   479→          });
   480→          if (jiraRes.ok) {
   481→            const jiraData = await jiraRes.json();
   482→            for (const issue of jiraData.issues || []) {
   483→              const jiraStatus = issue.fields?.status?.name?.toLowerCase() || '';
   484→              if (jiraStatus.includes('to do') || jiraStatus.includes('todo')) {
   485→                log(`${issue.key} moved back to To Do in Jira — resetting`);
   486→                resetKeys.add(issue.key);
   487→                delete taskStatuses[issue.key];
   488→                delete taskPrUrls[issue.key];
   489→                serverFetch(`/api/tasks/${issue.key}`, 'DELETE').catch(() => {});
   490→              }
   491→            }
   492→          }
   493→        } catch {
   494→          // Jira API call failed — skip the check
   495→        }
   496→      }
   497→
   498→      for (const task of tasks) {
   499→        if (resetKeys.has(task.key)) continue;
   500→        taskStatuses[task.key] = task.status;
   501→        if (task.prUrl) taskPrUrls[task.key] = task.prUrl;
   502→        const badge = document.querySelector(`[${BADGE_ATTR}="${task.key}"]`);
   503→        if (badge) {
   504→          updateBadgeState(badge, task.key, task.status);
   505→        }
   506→      }
   507→      persistStatuses();
   508→      log('Synced', tasks.length, 'task statuses from server');
   509→    } catch {
   510→      // Server not running
   511→    }
   512→  }
   513→
   514→  function connectWebSocket() {
   515→    const wsUrl = serverUrl.replace(/^http/, 'ws') + '/ws';
   516→    log('Connecting WebSocket:', wsUrl);
   517→
   518→    try {
   519→      ws = new WebSocket(wsUrl);
   520→    } catch {
   521→      log('WebSocket connection failed, retrying in', WS_RECONNECT_DELAY, 'ms');
   522→      setTimeout(connectWebSocket, WS_RECONNECT_DELAY);
   523→      return;
   524→    }
   525→
   526→    ws.onopen = async () => {
   527→      log('WebSocket connected');
   528→      // Restore task statuses from server (in case page was refreshed)
   529→      await syncTaskStatuses();
   530→    };
   531→
   532→    ws.onmessage = (event) => {
   533→      try {
   534→        const msg = JSON.parse(event.data);
   535→        handleServerMessage(msg);
   536→      } catch {
   537→        // ignore malformed messages
   538→      }
   539→    };
   540→
   541→    ws.onclose = () => {
   542→      log('WebSocket disconnected, reconnecting...');
   543→      ws = null;
   544→      setTimeout(connectWebSocket, WS_RECONNECT_DELAY);
   545→    };
   546→
   547→    ws.onerror = () => {
   548→      // onclose will fire after this, triggering reconnect
   549→    };
   550→  }
   551→
   552→  function handleServerMessage(msg) {
   553→    if (msg.type === 'task-status-changed' || msg.type === 'task-created' || msg.type === 'task-completed') {
   554→      const task = msg.task;
   555→      if (!task?.key) return;
   556→
   557→      const oldStatus = taskStatuses[task.key];
   558→      taskStatuses[task.key] = task.status;
   559→      if (task.prUrl) taskPrUrls[task.key] = task.prUrl;
   560→      persistStatuses();
   561→
   562→      // Update badge
   563→      const badge = document.querySelector(`[${BADGE_ATTR}="${task.key}"]`);
   564→      if (badge) {
   565→        updateBadgeState(badge, task.key, task.status);
   566→      }
   567→
   568→      // Update Jira when task completes: transition + comment
   569→      if (task.status === 'completed' && oldStatus !== 'completed') {
   570→        if (boardConfig?.transitions?.inReview) {
   571→          transitionIssue(task.key, boardConfig.transitions.inReview.name);
   572→        }
   573→        // Plan tasks: comment is posted via task-plan-ready (after server reads the plan file)
   574→        if (task.taskMode !== 'plan') {
   575→          postCompletionComment(task);
   576→        }
   577→      }
   578→
   579→      log(`Task ${task.key}: ${oldStatus || 'new'} → ${task.status}`);
   580→    }
   581→
   582→    // Server tells us to update Jira status — only for in-progress (completed is handled by task-status-changed)
   583→    if (msg.type === 'update-jira-status' && msg.issueKey && msg.pipelineStatus) {
   584→      if (msg.pipelineStatus === 'in-progress' && boardConfig?.transitions?.inProgress) {
   585→        transitionIssue(msg.issueKey, boardConfig.transitions.inProgress.name);
   586→      }
   587→    }
   588→
   589→    if (msg.type === 'task-plan-ready' && msg.taskKey && msg.planContent) {
   590→      postJiraComment(msg.taskKey, msg.planContent);
   591→    }
   592→  }
   593→
   594→  init().catch(err => warn('Init failed:', err));
   595→})();
   596→

