     1→/**
     2→ * Guided board configuration UI.
     3→ * Shows a modal on first visit to an unconfigured board.
     4→ * Reads column names from Jira REST API (via background worker).
     5→ */
     6→
     7→// @ts-check
     8→/* global chrome */
     9→
    10→const BoardConfig = {
    11→  /**
    12→   * Show the configuration modal.
    13→   * @param {string} boardId
    14→   * @param {function} onSave - called with the saved config
    15→   */
    16→  async show(boardId, onSave) {
    17→    console.log('[Jiranimo] Loading board columns from API...');
    18→
    19→    // Get columns from Jira API via background worker
    20→    const columns = await this._fetchBoardColumns(boardId);
    21→    console.log('[Jiranimo] Board columns:', columns);
    22→
    23→    if (columns.length === 0) {
    24→      console.warn('[Jiranimo] No columns found — falling back to defaults');
    25→      columns.push('To Do', 'In Progress', 'Done');
    26→    }
    27→
    28→    // Create overlay
    29→    const overlay = document.createElement('div');
    30→    overlay.className = 'jiranimo-config-overlay';
    31→
    32→    const modal = document.createElement('div');
    33→    modal.className = 'jiranimo-config-modal';
    34→
    35→    const columnOptions = columns.map(c => `<option value="${c}">${c}</option>`).join('');
    36→
    37→    modal.innerHTML = `
    38→      <h2>Configure Jiranimo for this board</h2>
    39→
    40→      <label for="jiranimo-in-progress">Which column means "In Progress"?</label>
    41→      <select id="jiranimo-in-progress">
    42→        <option value="">-- Skip --</option>
    43→        ${columnOptions}
    44→      </select>
    45→
    46→      <label for="jiranimo-in-review">Which column means "In Review" / "Done"?</label>
    47→      <select id="jiranimo-in-review">
    48→        <option value="">-- Skip --</option>
    49→        ${columnOptions}
    50→      </select>
    51→
    52→      <button id="jiranimo-save-config">Save Configuration</button>
    53→    `;
    54→
    55→    overlay.appendChild(modal);
    56→    document.body.appendChild(overlay);
    57→
    58→    // Pre-select likely columns
    59→    const inProgressSelect = modal.querySelector('#jiranimo-in-progress');
    60→    const inReviewSelect = modal.querySelector('#jiranimo-in-review');
    61→    for (const opt of inProgressSelect.options) {
    62→      if (opt.value.toLowerCase().includes('progress')) { opt.selected = true; break; }
    63→    }
    64→    for (const opt of inReviewSelect.options) {
    65→      if (opt.value.toLowerCase().includes('done') || opt.value.toLowerCase().includes('review')) { opt.selected = true; break; }
    66→    }
    67→
    68→    // Close on overlay click
    69→    overlay.addEventListener('click', (e) => {
    70→      if (e.target === overlay) {
    71→        overlay.remove();
    72→      }
    73→    });
    74→
    75→    // Save handler
    76→    modal.querySelector('#jiranimo-save-config').addEventListener('click', async () => {
    77→      const inProgressCol = inProgressSelect.value;
    78→      const inReviewCol = inReviewSelect.value;
    79→
    80→      const transitions = await this._resolveTransitions(inProgressCol, inReviewCol);
    81→      const projectKey = this._extractProjectKey();
    82→
    83→      const config = {
    84→        boardId,
    85→        projectKey,
    86→        transitions,
    87→      };
    88→
    89→      console.log('[Jiranimo] Saving board config:', JSON.stringify(config));
    90→      await chrome.storage.local.set({ [`boardConfig_${boardId}`]: config });
    91→
    92→      overlay.remove();
    93→      onSave(config);
    94→    });
    95→  },
    96→
    97→  /**
    98→   * Fetch board columns from Jira Agile REST API.
    99→   * Calls the API directly from the content script (session cookies are available).
   100→   * @param {string} boardId
   101→   * @returns {Promise<string[]>}
   102→   */
   103→  async _fetchBoardColumns(boardId) {
   104→    try {
   105→      const host = location.origin; // e.g. "https://niryosef89.atlassian.net"
   106→      const url = `${host}/rest/agile/1.0/board/${boardId}/configuration`;
   107→      console.log('[Jiranimo] Fetching board config from:', url);
   108→      const res = await fetch(url, { credentials: 'include' });
   109→      if (!res.ok) {
   110→        console.warn('[Jiranimo] Board config API returned:', res.status);
   111→        return [];
   112→      }
   113→      const data = await res.json();
   114→      const columns = (data.columnConfig?.columns || []).map(c => c.name);
   115→      console.log('[Jiranimo] Columns from API:', columns);
   116→      return columns;
   117→    } catch (err) {
   118→      console.warn('[Jiranimo] Failed to fetch board columns:', err);
   119→      return [];
   120→    }
   121→  },
   122→
   123→  /**
   124→   * Try to resolve column names to Jira transition IDs.
   125→   * @param {string} inProgressCol
   126→   * @param {string} inReviewCol
   127→   * @returns {Promise<{inProgress?: {name: string, id: string}, inReview?: {name: string, id: string}}>}
   128→   */
   129→  async _resolveTransitions(inProgressCol, inReviewCol) {
   130→    const result = {};
   131→    if (!inProgressCol && !inReviewCol) return result;
   132→
   133→    const sampleKey = this._findSampleIssueKey();
   134→    if (!sampleKey) return result;
   135→
   136→    try {
   137→      // Fetch transitions directly from content script (has session cookies)
   138→      const res = await fetch(`${location.origin}/rest/api/3/issue/${sampleKey}/transitions`, { credentials: 'include' });
   139→      if (!res.ok) return result;
   140→      const data = await res.json();
   141→      const transitions = data.transitions || [];
   142→
   143→      if (inProgressCol) {
   144→        const match = transitions.find(t =>
   145→          t.name.toLowerCase() === inProgressCol.toLowerCase()
   146→        );
   147→        if (match) result.inProgress = { name: match.name, id: match.id };
   148→      }
   149→
   150→      if (inReviewCol) {
   151→        const match = transitions.find(t =>
   152→          t.name.toLowerCase() === inReviewCol.toLowerCase()
   153→        );
   154→        if (match) result.inReview = { name: match.name, id: match.id };
   155→      }
   156→    } catch (err) {
   157→      console.warn('[Jiranimo] Failed to resolve transitions:', err);
   158→    }
   159→
   160→    return result;
   161→  },
   162→
   163→  /**
   164→   * Find any issue key visible on the board.
   165→   * @returns {string|null}
   166→   */
   167→  _findSampleIssueKey() {
   168→    const keyPattern = /\b[A-Z][A-Z0-9]+-\d+\b/;
   169→    const links = document.querySelectorAll('a[href*="/browse/"]');
   170→    for (const link of links) {
   171→      const match = link.textContent?.match(keyPattern);
   172→      if (match) return match[0];
   173→    }
   174→    const match = document.body.textContent?.match(keyPattern);
   175→    return match ? match[0] : null;
   176→  },
   177→
   178→  /**
   179→   * Extract project key from the URL.
   180→   * @returns {string}
   181→   */
   182→  _extractProjectKey() {
   183→    const match = location.pathname.match(/\/projects\/([^/]+)/);
   184→    return match ? match[1] : '';
   185→  },
   186→};
   187→
   188→if (typeof module !== 'undefined' && module.exports) {
   189→  module.exports = { BoardConfig };
   190→} else if (typeof globalThis !== 'undefined') {
   191→  globalThis.BoardConfig = BoardConfig;
   192→}
