     1→/**
     2→ * Jiranimo background service worker.
     3→ *
     4→ * NOTE: This worker does NOT make Jira API calls. All Jira communication
     5→ * goes through the content script which has session cookies.
     6→ *
     7→ * This worker handles:
     8→ * - Extension settings
     9→ * - Dev mode auto-reload (listens for reload signal from server WebSocket)
    10→ */
    11→
    12→// @ts-check
    13→
    14→const LOG = '[Jiranimo BG]';
    15→let serverUrl = 'http://localhost:3456';
    16→
    17→// Load settings on startup
    18→chrome.storage.local.get(['serverUrl'], (result) => {
    19→  if (result.serverUrl) serverUrl = result.serverUrl;
    20→});
    21→
    22→// Listen for settings changes
    23→chrome.storage.onChanged.addListener((changes) => {
    24→  if (changes.serverUrl?.newValue) {
    25→    serverUrl = changes.serverUrl.newValue;
    26→  }
    27→});
    28→
    29→// --- Dev mode auto-reload ---
    30→// Connect to server WebSocket and listen for extension-reload signals.
    31→// In production the server isn't on localhost, so this silently fails.
    32→function connectForAutoReload() {
    33→  const wsUrl = serverUrl.replace(/^http/, 'ws') + '/ws';
    34→  try {
    35→    const ws = new WebSocket(wsUrl);
    36→
    37→    ws.onmessage = (event) => {
    38→      try {
    39→        const msg = JSON.parse(event.data);
    40→        if (msg.type === 'extension-reload') {
    41→          console.log(LOG, 'Reload signal received — reloading extension');
    42→          chrome.runtime.reload();
    43→        }
    44→      } catch {
    45→        // ignore
    46→      }
    47→    };
    48→
    49→    ws.onclose = () => {
    50→      // Reconnect after delay (server might restart during dev)
    51→      setTimeout(connectForAutoReload, 5000);
    52→    };
    53→
    54→    ws.onerror = () => {
    55→      // Will trigger onclose → reconnect
    56→    };
    57→  } catch {
    58→    // No server running — retry later
    59→    setTimeout(connectForAutoReload, 10000);
    60→  }
    61→}
    62→
    63→connectForAutoReload();
    64→
    65→// Proxy Jiranimo server API calls from content scripts.
    66→// Content scripts run in the page's origin (atlassian.net), which Chrome's
    67→// Private Network Access policy blocks from fetching localhost directly.
    68→// The background service worker has extension origin and can access localhost freely.
    69→chrome.runtime.onMessage.addListener((msg, _sender, sendResponse) => {
    70→  if (msg.type === 'server-fetch') {
    71→    fetch(serverUrl + msg.path, {
    72→      method: msg.method || 'GET',
    73→      headers: msg.body ? { 'Content-Type': 'application/json' } : undefined,
    74→      body: msg.body ? JSON.stringify(msg.body) : undefined,
    75→    })
    76→      .then(async res => {
    77→        const data = await res.json().catch(() => ({}));
    78→        sendResponse({ ok: res.ok, status: res.status, data });
    79→      })
    80→      .catch(err => sendResponse({ ok: false, error: err.message }));
    81→    return true; // keep channel open for async response
    82→  }
    83→});
    84→

