     1→import { WebSocketServer, WebSocket } from 'ws';
     2→import type { Server } from 'node:http';
     3→import type { PipelineManager } from '../pipeline/manager.js';
     4→import type { TaskRecord, TaskStatus } from '../state/types.js';
     5→
     6→export interface WsMessage {
     7→  type: string;
     8→  [key: string]: unknown;
     9→}
    10→
    11→/**
    12→ * WebSocket handler with offline message queue.
    13→ * When no clients are connected, messages are queued.
    14→ * When a client reconnects, all queued messages are delivered.
    15→ */
    16→export class WsHandler {
    17→  private wss: WebSocketServer;
    18→  private offlineQueue: WsMessage[] = [];
    19→  private maxQueueSize = 1000;
    20→
    21→  constructor(server: Server, pipeline: PipelineManager) {
    22→    this.wss = new WebSocketServer({ server, path: '/ws' });
    23→
    24→    this.wss.on('connection', (client) => {
    25→      console.log('[WS] Client connected, draining offline queue:', this.offlineQueue.length, 'messages');
    26→      this.drainQueue(client);
    27→    });
    28→
    29→    // Pipeline events → broadcast or queue
    30→    pipeline.on('task-created', (task: TaskRecord) => {
    31→      this.send({ type: 'task-created', task });
    32→    });
    33→
    34→    pipeline.on('task-status-changed', (task: TaskRecord, oldStatus: TaskStatus) => {
    35→      this.send({ type: 'task-status-changed', taskKey: task.key, oldStatus, newStatus: task.status, task });
    36→
    37→      // Tell extension to update Jira status — extension uses its board config to pick the right transition
    38→      if (task.status === 'in-progress' || task.status === 'completed' || task.status === 'failed') {
    39→        this.send({ type: 'update-jira-status', issueKey: task.key, pipelineStatus: task.status });
    40→      }
    41→    });
    42→
    43→    pipeline.on('task-output', (taskKey: string, line: string) => {
    44→      this.send({ type: 'task-output', taskKey, line });
    45→    });
    46→
    47→    pipeline.on('task-completed', (task: TaskRecord) => {
    48→      this.send({ type: 'task-completed', task });
    49→    });
    50→
    51→    pipeline.on('task-plan-ready', (taskKey: string, planContent: string) => {
    52→      this.send({ type: 'task-plan-ready', taskKey, planContent });
    53→    });
    54→  }
    55→
    56→  /** Send a message to all connected clients, or queue it if none are connected. */
    57→  send(msg: WsMessage): void {
    58→    const data = JSON.stringify(msg);
    59→    let delivered = false;
    60→
    61→    for (const client of this.wss.clients) {
    62→      if (client.readyState === WebSocket.OPEN) {
    63→        client.send(data);
    64→        delivered = true;
    65→      }
    66→    }
    67→
    68→    if (!delivered) {
    69→      this.enqueue(msg);
    70→    }
    71→  }
    72→
    73→  private enqueue(msg: WsMessage): void {
    74→    // Don't queue noisy output messages
    75→    if (msg.type === 'task-output') return;
    76→
    77→    this.offlineQueue.push(msg);
    78→    if (this.offlineQueue.length > this.maxQueueSize) {
    79→      this.offlineQueue.shift();
    80→    }
    81→  }
    82→
    83→  /** Send all queued messages to a newly connected client. */
    84→  private drainQueue(client: WebSocket): void {
    85→    for (const msg of this.offlineQueue) {
    86→      if (client.readyState === WebSocket.OPEN) {
    87→        client.send(JSON.stringify(msg));
    88→      }
    89→    }
    90→    this.offlineQueue = [];
    91→  }
    92→
    93→  get queueLength(): number {
    94→    return this.offlineQueue.length;
    95→  }
    96→
    97→  get server(): WebSocketServer {
    98→    return this.wss;
    99→  }
   100→}

