.jiranimo-icon {
  display: inline-flex;
  align-items: center;
  cursor: pointer;
  vertical-align: middle;
  margin-left: 4px;
  flex-shrink: 0;
  transition: color 0.15s, transform 0.2s cubic-bezier(0.34, 1.56, 0.64, 1);
}

.jiranimo-icon:hover {
  transform: scale(1.4);
}

.jiranimo-icon svg {
  width: 1em;
  height: 1em;
  display: block;
}

.jiranimo-icon.idle { color: #0052cc; }
.jiranimo-icon.idle:hover { color: #0065ff; }

.jiranimo-icon.sending {
  color: #6b778c;
  cursor: wait;
  animation: jiranimo-spin 1s linear infinite;
}

.jiranimo-icon.queued {
  color: #ff991f;
  animation: jiranimo-pulse 1.5s ease-in-out infinite;
}

.jiranimo-icon.in-progress {
  color: #0052cc;
  animation: jiranimo-sparkle 1.2s ease-in-out infinite;
}

.jiranimo-icon.completed { color: #36b37e; }
.jiranimo-icon.completed:hover { color: #2d9f6f; }

.jiranimo-icon.failed { color: #de350b; }
.jiranimo-icon.failed:hover { color: #ff5630; }

@keyframes jiranimo-spin {
  from { transform: rotate(0deg); }
  to   { transform: rotate(360deg); }
}

@keyframes jiranimo-pulse {
  0%, 100% { opacity: 1; }
  50%      { opacity: 0.4; }
}

@keyframes jiranimo-sparkle {
  0%   { transform: scale(1)   rotate(0deg);   opacity: 1; }
  25%  { transform: scale(1.3) rotate(90deg);  opacity: 0.6; }
  50%  { transform: scale(0.85) rotate(180deg); opacity: 1; }
  75%  { transform: scale(1.3) rotate(270deg); opacity: 0.6; }
  100% { transform: scale(1)   rotate(360deg); opacity: 1; }
}

.jiranimo-config-overlay {
  position: fixed;
  top: 0; left: 0; right: 0; bottom: 0;
  background: rgba(9, 30, 66, 0.54);
  z-index: 10000;
  display: flex;
  align-items: center;
  justify-content: center;
}

.jiranimo-config-modal {
  background: #fff;
  border-radius: 8px;
  padding: 24px;
  width: 420px;
  max-width: 90vw;
  box-shadow: 0 8px 24px rgba(0,0,0,0.3);
  color: #172b4d;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
}

.jiranimo-config-modal h2 {
  margin: 0 0 16px;
  font-size: 18px;
}

.jiranimo-config-modal label {
  display: block;
  margin: 12px 0 4px;
  font-size: 12px;
  font-weight: 600;
  color: #6b778c;
}

.jiranimo-config-modal select,
.jiranimo-config-modal input {
  width: 100%;
  padding: 8px;
  border: 1px solid #dfe1e6;
  border-radius: 4px;
  font-size: 14px;
}

.jiranimo-config-modal button {
  margin-top: 16px;
  padding: 8px 16px;
  background: #0052cc;
  color: #fff;
  border: none;
  border-radius: 4px;
  font-size: 14px;
  cursor: pointer;
}

.jiranimo-config-modal button:hover {
  background: #0065ff;
}

/* ── About overlay ───────────────────────────────────────────────────── */

.jiranimo-about-overlay {
  position: fixed;
  top: 0; left: 0; right: 0; bottom: 0;
  background: rgba(9, 30, 66, 0.54);
  z-index: 10001;
  display: flex;
  align-items: center;
  justify-content: center;
  opacity: 0;
  transition: opacity 0.2s ease;
}

.jiranimo-about-overlay.jiranimo-about-visible {
  opacity: 1;
}

.jiranimo-about-overlay.jiranimo-about-visible .jiranimo-about-modal {
  transform: translateY(0) scale(1);
}

.jiranimo-about-modal {
  background: #fff;
  border-radius: 12px;
  padding: 32px;
  width: 480px;
  max-width: 92vw;
  max-height: 80vh;
  overflow-y: auto;
  box-shadow: 0 16px 48px rgba(0,0,0,0.35);
  color: #172b4d;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  position: relative;
  transform: translateY(-16px) scale(0.97);
  transition: transform 0.2s ease;
}

.jiranimo-about-header {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 8px;
}

.jiranimo-about-logo {
  font-size: 28px;
  color: #0052cc;
  line-height: 1;
}

.jiranimo-about-header h2 {
  margin: 0;
  font-size: 22px;
  font-weight: 700;
  color: #172b4d;
}

.jiranimo-about-version {
  font-size: 12px;
  color: #6b778c;
  background: #f4f5f7;
  border-radius: 4px;
  padding: 2px 6px;
  font-weight: 500;
}

.jiranimo-about-tagline {
  margin: 0 0 20px;
  font-size: 14px;
  color: #6b778c;
}

.jiranimo-about-section {
  margin-bottom: 20px;
}

.jiranimo-about-section h3 {
  margin: 0 0 8px;
  font-size: 12px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  color: #6b778c;
}

.jiranimo-about-section ul {
  margin: 0;
  padding-left: 18px;
}

.jiranimo-about-section li {
  font-size: 14px;
  margin-bottom: 6px;
  color: #172b4d;
  line-height: 1.5;
}

.jiranimo-about-section p {
  margin: 0;
  font-size: 14px;
  color: #172b4d;
  line-height: 1.5;
}

.jiranimo-about-section a {
  color: #0052cc;
  text-decoration: none;
}

.jiranimo-about-section a:hover {
  text-decoration: underline;
}

